import useCanvasObjects from "../hooks/useCanvasObjects";

function AppContainer() {

    const {
        canvasRef,
        objects,
        newObject,
        startDragging,
        dragging,
        stopDragging
    } = useCanvasObjects();

    return (
        <div className="app-container">

            <header className="header">
                <h1>🎵 Sound Landscape</h1>
            </header>

            <div className="main">

                <aside className="sidebar">
                    <button onClick={newObject}>
                        Добавить объект
                    </button>
                </aside>

                <div
                    className="canvas-container"
                    ref={canvasRef}
                    onMouseMove={dragging}
                    onMouseUp={stopDragging}
                    style={{ position: "relative" }}
                >

                    {objects.map(obj => (
                        <div
                            key={obj.id}
                            className="obj"
                            onMouseDown={(e) => startDragging(obj.id, e)}
                            style={{
                                position: "absolute",
                                left: obj.left,
                                top: obj.top
                            }}
                        />
                    ))}

                </div>

            </div>

        </div>
    );
}

export default AppContainer;
